import burguers from "../../data-json/burgers.json"


function Burguers( setCarrito, carrito ) {

    return (
      <div className='productos-cont'>
  
        <h2 id='burguers'>BURGUERS</h2>
  
        <div className="burguers" >
          {
            burguers &&
            burguers.map((elemento) => (
              <Tarjeta key={elemento.id} elemento={elemento} id={elemento.id} titulo={elemento.titulo} img={elemento.img} precio={elemento.precio} descripcion={elemento.descripcion} setCarrito={setCarrito} carrito={carrito}/>
            ))
          } 
        </div>
      </div>
    )
  };
 
export default Burguers;
